  std::optional<double> tax_rate;
};

struct OrderMetrics {
  int item_id;
  int order_id;
  int product_id;
  double unit_price;
  int quantity;
  double discount_rate;
  double tax_rate;
  double gross_total;
  double discounted_total;
  double final_total;
  double unit_cost;
  int quantity_group;
  double estimated_profit;
};

/**
 * Calculate per-item order metrics by loading the provided items into a temporary SQLite table
 * and evaluating SQL expressions for totals, discounts, taxes, cost, grouping, and estimated profit.
 * @param items Vector of OrderItem records to analyze.
 * @return std::vector<OrderMetrics> Analysis results for each order item.
 */
std::vector<OrderMetrics> calculate_order_metrics_impl(const std::vector<OrderItem>& items) {
  using namespace sqlgen::literals;

  // 1. Create an in-memory SQLite database connection
  auto conn = sqlgen::sqlite::connect();

  // 2. Create a temporary table from the input vector of OrderItem
  auto write_result = sqlgen::write(conn, items);
  if (!write_result) {
    throw std::runtime_error("Failed to write data to database");
  }

  // 3. Use sqlgen's select_from with column literals and arithmetic operations
  auto query = sqlgen::select_from<OrderItem>(
    "item_id"_c,
    "order_id"_c,
    "product_id"_c,
    "unit_price"_c,
    "quantity"_c,
    "discount_rate"_c,
    "tax_rate"_c,

    // Arithmetic operations for business metrics
    ("unit_price"_c * "quantity"_c) | sqlgen::as<"gross_total">,
    ("unit_price"_c * "quantity"_c * (1 - sqlgen::coalesce("discount_rate"_c, 0.0)/100.0)) | sqlgen::as<"discounted_total">,
    (("unit_price"_c * "quantity"_c * (1 - sqlgen::coalesce("discount_rate"_c, 0.0)/100.0)) * (1 + sqlgen::coalesce("tax_rate"_c, 0.0)/100.0)) | sqlgen::as<"final_total">,
    ("unit_price"_c * "quantity"_c / "quantity"_c) | sqlgen::as<"unit_cost">,
    ("quantity"_c % 10) | sqlgen::as<"quantity_group">,
    ("unit_price"_c * 0.3) | sqlgen::as<"estimated_profit">
  );

  // 4. Map the result to OrderMetrics objects
  auto result = query(conn);
  if (!result) {
    throw std::runtime_error("Failed to read data from database");
  }

  // 5. Return the vector of OrderMetrics
  return result.value();
}

}  // namespace calculate_order_metrics

